     1→import { useState } from 'react';
     2→import { UserCheck, Plus, Search, Phone, Mail, MapPin, Star, Edit2, Trash2, X, ChevronDown, ChevronUp, Building2, TrendingUp, Users } from 'lucide-react';
     3→import { useContacts } from '../../hooks/useData';
     4→import { toast } from 'sonner';
     5→
     6→type AnyRow = Record<string, unknown>;
     7→
     8→const CONTACT_TYPES = ['Client','Consultant','Subcontractor','Supplier','Statutory Body','Insurer','Solicitor','Other'];
     9→const STATUS_OPTIONS = ['Active','Inactive','Prospect','Do Not Contact'];
    10→
    11→const typeColour: Record<string,string> = {
    12→  'Client':'bg-blue-100 text-blue-800','Consultant':'bg-purple-100 text-purple-700',
    13→  'Subcontractor':'bg-orange-100 text-orange-700','Supplier':'bg-green-100 text-green-700',
    14→  'Statutory Body':'bg-gray-100 text-gray-700','Insurer':'bg-teal-100 text-teal-700',
    15→  'Solicitor':'bg-red-100 text-red-700','Other':'bg-gray-100 text-gray-600',
    16→};
    17→
    18→const statusColour: Record<string,string> = {
    19→  'Active':'bg-green-100 text-green-800','Inactive':'bg-gray-100 text-gray-600',
    20→  'Prospect':'bg-yellow-100 text-yellow-800','Do Not Contact':'bg-red-100 text-red-700',
    21→};
    22→
    23→const emptyForm = { name:'',company:'',type:'Client',email:'',phone:'',address:'',status:'Active',rating:'3',notes:'',website:'' };
    24→
    25→export function CRM() {
    26→  const { useList, useCreate, useUpdate, useDelete } = useContacts;
    27→  const { data: raw = [], isLoading } = useList();
    28→  const contacts = raw as AnyRow[];
    29→  const createMutation = useCreate();
    30→  const updateMutation = useUpdate();
    31→  const deleteMutation = useDelete();
    32→
    33→  const [subTab, setSubTab] = useState<'contacts'|'pipeline'|'companies'>('contacts');
    34→  const [search, setSearch] = useState('');
    35→  const [typeFilter, setTypeFilter] = useState('All');
    36→  const [statusFilter, setStatusFilter] = useState('All');
    37→  const [showModal, setShowModal] = useState(false);
    38→  const [editing, setEditing] = useState<AnyRow | null>(null);
    39→  const [form, setForm] = useState({ ...emptyForm });
    40→  const [expanded, setExpanded] = useState<string | null>(null);
    41→
    42→  const filtered = contacts.filter(c => {
    43→    const name = String(c.name??'').toLowerCase();
    44→    const company = String(c.company??'').toLowerCase();
    45→    const matchSearch = name.includes(search.toLowerCase()) || company.includes(search.toLowerCase());
    46→    const matchType = typeFilter === 'All' || c.type === typeFilter;
    47→    const matchStatus = statusFilter === 'All' || c.status === statusFilter;
    48→    return matchSearch && matchType && matchStatus;
    49→  });
    50→
    51→  const clientCount = contacts.filter(c=>c.type==='Client').length;
    52→  const consultantCount = contacts.filter(c=>c.type==='Consultant').length;
    53→  const activeCount = contacts.filter(c=>c.status==='Active').length;
    54→  const prospectCount = contacts.filter(c=>c.status==='Prospect').length;
    55→
    56→  // Pipeline data
    57→  const pipeline = CONTACT_TYPES.map(type => ({
    58→    type,
    59→    contacts: contacts.filter(c=>c.type===type),
    60→    count: contacts.filter(c=>c.type===type).length,
    61→  })).filter(g=>g.count>0);
    62→
    63→  // Companies grouping
    64→  const companiesMap = new Map<string, AnyRow[]>();
    65→  contacts.forEach(c => {
    66→    const co = String(c.company||'(No Company)');
    67→    if (!companiesMap.has(co)) companiesMap.set(co, []);
    68→    companiesMap.get(co)!.push(c);
    69→  });
    70→  const companies = Array.from(companiesMap.entries())
    71→    .map(([name, members]) => ({ name, members, count: members.length }))
    72→    .sort((a,b) => b.count - a.count);
    73→
    74→  function openCreate() { setEditing(null); setForm({ ...emptyForm }); setShowModal(true); }
    75→  function openEdit(c: AnyRow) {
    76→    setEditing(c);
    77→    setForm({ name:String(c.name??''),company:String(c.company??''),type:String(c.type??'Client'),email:String(c.email??''),phone:String(c.phone??''),address:String(c.address??''),status:String(c.status??'Active'),rating:String(c.rating??'3'),notes:String(c.notes??''),website:String(c.website??'') });
    78→    setShowModal(true);
    79→  }
    80→
    81→  async function handleSubmit(e: React.FormEvent) {
    82→    e.preventDefault();
    83→    const payload = { ...form, rating:Number(form.rating)||3 };
    84→    if (editing) { await updateMutation.mutateAsync({ id:String(editing.id), data:payload }); toast.success('Contact updated'); }
    85→    else { await createMutation.mutateAsync(payload); toast.success('Contact added'); }
    86→    setShowModal(false);
    87→  }
    88→
    89→  async function handleDelete(id: string) {
    90→    if (!confirm('Delete this contact?')) return;
    91→    await deleteMutation.mutateAsync(id); toast.success('Contact deleted');
    92→  }
    93→
    94→  return (
    95→    <div className="p-6 space-y-6">
    96→      <div className="flex items-center justify-between">
    97→        <div>
    98→          <h1 className="text-2xl font-bold text-gray-900">CRM</h1>
    99→          <p className="text-sm text-gray-500 mt-1">Clients, consultants & supply chain contacts</p>
   100→        </div>
   101→        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 text-sm font-medium">
   102→          <Plus size={16}/><span>Add Contact</span>
   103→        </button>
   104→      </div>
   105→
   106→      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
   107→        {[
   108→          { label:'Clients', value:clientCount, icon:Building2, colour:'text-blue-600', bg:'bg-blue-50' },
   109→          { label:'Consultants', value:consultantCount, icon:UserCheck, colour:'text-purple-600', bg:'bg-purple-50' },
   110→          { label:'Active', value:activeCount, icon:UserCheck, colour:'text-green-600', bg:'bg-green-50' },
   111→          { label:'Prospects', value:prospectCount, icon:Star, colour:'text-yellow-600', bg:'bg-yellow-50' },
   112→        ].map(kpi=>(
   113→          <div key={kpi.label} className="bg-white rounded-xl border border-gray-200 p-4">
   114→            <div className="flex items-center gap-3">
   115→              <div className={`p-2 rounded-lg ${kpi.bg}`}><kpi.icon size={20} className={kpi.colour}/></div>
   116→              <div><p className="text-xs text-gray-500">{kpi.label}</p><p className="text-xl font-bold text-gray-900">{kpi.value}</p></div>
   117→            </div>
   118→          </div>
   119→        ))}
   120→      </div>
   121→
   122→      {/* Sub-tab nav */}
   123→      <div className="flex gap-1 border-b border-gray-200">
   124→        {([
   125→          { key:'contacts', label:'All Contacts', icon:UserCheck, count:contacts.length },
   126→          { key:'pipeline', label:'By Type',      icon:TrendingUp, count:null },
   127→          { key:'companies',label:'Companies',    icon:Users,      count:companiesMap.size },
   128→        ] as const).map(t=>(
   129→          <button key={t.key} onClick={()=>setSubTab(t.key)}
   130→            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${subTab===t.key?'border-orange-600 text-orange-600':'border-transparent text-gray-500 hover:text-gray-700'}`}>
   131→            <t.icon size={14}/>{t.label}
   132→            {t.count!==null && <span className="text-xs px-1.5 py-0.5 rounded-full bg-gray-100 text-gray-600">{t.count}</span>}
   133→          </button>
   134→        ))}
   135→      </div>
   136→
   137→      {subTab==='contacts' && <div className="flex flex-wrap gap-3 items-center bg-white rounded-xl border border-gray-200 p-4">
   138→        <div className="relative flex-1 min-w-48">
   139→          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"/>
   140→          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search name or company…" className="w-full pl-9 pr-4 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"/>
   141→        </div>
   142→        <select value={typeFilter} onChange={e=>setTypeFilter(e.target.value)} className="text-sm border border-gray-200 rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-orange-500">
   143→          {['All',...CONTACT_TYPES].map(t=><option key={t}>{t}</option>)}
   144→        </select>
   145→        <select value={statusFilter} onChange={e=>setStatusFilter(e.target.value)} className="text-sm border border-gray-200 rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-orange-500">
   146→          {['All',...STATUS_OPTIONS].map(s=><option key={s}>{s}</option>)}
   147→        </select>
   148→        <span className="text-sm text-gray-500 ml-auto">{filtered.length} contacts</span>
   149→      </div>}
   150→
   151→      {/* ── BY TYPE tab ───────────────────────────────────────── */}
   152→      {subTab==='pipeline' && (
   153→        <div className="space-y-4">
   154→          {pipeline.map(group=>(
   155→            <div key={group.type} className="bg-white rounded-xl border border-gray-200 overflow-hidden">
   156→              <div className="flex items-center justify-between px-4 py-3 bg-gray-50 border-b border-gray-200">
   157→                <div className="flex items-center gap-2">
   158→                  <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${typeColour[group.type]??'bg-gray-100 text-gray-700'}`}>{group.type}</span>
   159→                  <span className="text-sm font-semibold text-gray-700">{group.count} contact{group.count!==1?'s':''}</span>
   160→                </div>
   161→              </div>
   162→              <div className="divide-y divide-gray-50">
   163→                {group.contacts.map(c=>(
   164→                  <div key={String(c.id??'')} className="flex items-center gap-3 px-4 py-2.5 hover:bg-gray-50">
   165→                    <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-400 to-indigo-600 flex items-center justify-center text-white text-xs font-bold flex-shrink-0">
   166→                      {String(c.name??'?').split(' ').map((n:string)=>n[0]).slice(0,2).join('')}
   167→                    </div>
   168→                    <div className="flex-1 min-w-0">
   169→                      <p className="text-sm font-medium text-gray-900 truncate">{String(c.name??'')}</p>
   170→                      {!!c.company && <p className="text-xs text-gray-500 truncate">{String(c.company)}</p>}
   171→                    </div>
   172→                    <div className="hidden sm:flex items-center gap-3 text-xs text-gray-500">
   173→                      {!!c.email && <a href={`mailto:${c.email}`} className="flex items-center gap-1 text-blue-600 hover:underline"><Mail size={11}/>{String(c.email)}</a>}
   174→                      {!!c.phone && <a href={`tel:${c.phone}`} className="flex items-center gap-1 text-blue-600 hover:underline"><Phone size={11}/>{String(c.phone)}</a>}
   175→                    </div>
   176→                    <span className={`text-xs px-2 py-0.5 rounded-full font-medium flex-shrink-0 ${statusColour[String(c.status??'')] ?? 'bg-gray-100 text-gray-600'}`}>{String(c.status??'')}</span>
   177→                    <button onClick={()=>openEdit(c)} className="p-1 text-gray-400 hover:text-blue-600 rounded flex-shrink-0"><Edit2 size={13}/></button>
   178→                  </div>
   179→                ))}
   180→              </div>
   181→            </div>
   182→          ))}
   183→          {pipeline.length===0 && <div className="text-center py-16 text-gray-400 bg-white rounded-xl border border-gray-200"><TrendingUp size={40} className="mx-auto mb-3 opacity-30"/><p>No contacts yet</p></div>}
   184→        </div>
   185→      )}
   186→
   187→      {/* ── COMPANIES tab ─────────────────────────────────────── */}
   188→      {subTab==='companies' && (
   189→        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
   190→          {companies.length===0 && (
   191→            <div className="col-span-3 text-center py-16 text-gray-400 bg-white rounded-xl border border-gray-200"><Building2 size={40} className="mx-auto mb-3 opacity-30"/><p>No companies found</p></div>
   192→          )}
   193→          {companies.map(co=>(
   194→            <div key={co.name} className="bg-white rounded-xl border border-gray-200 overflow-hidden">
   195→              <div className="flex items-center gap-3 px-4 py-3 border-b border-gray-100">
   196→                <div className="w-9 h-9 rounded-lg bg-gradient-to-br from-indigo-400 to-purple-600 flex items-center justify-center text-white font-bold text-sm flex-shrink-0">
   197→                  {co.name.charAt(0)}
   198→                </div>
   199→                <div className="flex-1 min-w-0">
   200→                  <p className="font-semibold text-gray-900 truncate">{co.name}</p>
   201→                  <p className="text-xs text-gray-500">{co.count} contact{co.count!==1?'s':''}</p>
   202→                </div>
   203→              </div>
   204→              <div className="divide-y divide-gray-50">
   205→                {co.members.map(c=>(
   206→                  <div key={String(c.id??'')} className="flex items-center gap-3 px-4 py-2 hover:bg-gray-50">
   207→                    <div className="w-6 h-6 rounded-full bg-gradient-to-br from-blue-300 to-blue-500 flex items-center justify-center text-white text-xs font-bold flex-shrink-0">
   208→                      {String(c.name??'?')[0]}
   209→                    </div>
   210→                    <div className="flex-1 min-w-0">
   211→                      <p className="text-sm text-gray-900 truncate">{String(c.name??'')}</p>
   212→                    </div>
   213→                    <span className={`text-xs px-1.5 py-0.5 rounded-full font-medium flex-shrink-0 ${typeColour[String(c.type??'')] ?? 'bg-gray-100 text-gray-700'}`}>{String(c.type??'')}</span>
   214→                    <button onClick={()=>openEdit(c)} className="p-1 text-gray-400 hover:text-blue-600 rounded flex-shrink-0"><Edit2 size={12}/></button>
   215→                  </div>
   216→                ))}
   217→              </div>
   218→            </div>
   219→          ))}
   220→        </div>
   221→      )}
   222→
   223→      {/* ── ALL CONTACTS tab ──────────────────────────────────── */}
   224→      {subTab==='contacts' && isLoading ? (
   225→        <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-600"/></div>
   226→      ) : subTab==='contacts' && (
   227→        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
   228→          {filtered.length === 0 && (
   229→            <div className="col-span-3 text-center py-16 text-gray-400 bg-white rounded-xl border border-gray-200">
   230→              <UserCheck size={40} className="mx-auto mb-3 opacity-30"/><p>No contacts found</p>
   231→            </div>
   232→          )}
   233→          {filtered.map(c=>{
   234→            const id = String(c.id??'');
   235→            const isExp = expanded === id;
   236→            const rating = Number(c.rating??0);
   237→            return (
   238→              <div key={id} className="bg-white rounded-xl border border-gray-200 hover:shadow-md transition-shadow">
   239→                <div className="p-4 cursor-pointer" onClick={()=>setExpanded(isExp?null:id)}>
   240→                  <div className="flex items-start gap-3">
   241→                    <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-blue-400 to-indigo-600 flex items-center justify-center text-white font-bold text-sm flex-shrink-0">
   242→                      {String(c.name??'?').split(' ').map((n:string)=>n[0]).slice(0,2).join('')}
   243→                    </div>
   244→                    <div className="flex-1 min-w-0">
   245→                      <p className="font-semibold text-gray-900 truncate">{String(c.name??'Unknown')}</p>
   246→                      {!!c.company && <p className="text-sm text-gray-500 truncate flex items-center gap-1"><Building2 size={11}/>{String(c.company)}</p>}
   247→                    </div>
   248→                    <div className="flex gap-1 flex-shrink-0">
   249→                      <button onClick={e=>{e.stopPropagation();openEdit(c);}} className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded"><Edit2 size={13}/></button>
   250→                      <button onClick={e=>{e.stopPropagation();handleDelete(id);}} className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded"><Trash2 size={13}/></button>
   251→                    </div>
   252→                  </div>
   253→                  <div className="flex flex-wrap items-center gap-2 mt-3">
   254→                    <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${typeColour[String(c.type??'')] ?? 'bg-gray-100 text-gray-700'}`}>{String(c.type??'')}</span>
   255→                    <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${statusColour[String(c.status??'')] ?? 'bg-gray-100 text-gray-600'}`}>{String(c.status??'')}</span>
   256→                    {rating > 0 && (
   257→                      <div className="flex items-center gap-0.5 ml-auto">
   258→                        {[1,2,3,4,5].map(i=><Star key={i} size={10} className={i<=rating?'text-yellow-400 fill-yellow-400':'text-gray-200 fill-gray-200'}/>)}
   259→                      </div>
   260→                    )}
   261→                  </div>
   262→                  {(!!c.email || !!c.phone) && (
   263→                    <div className="flex flex-wrap gap-3 mt-3 text-xs">
   264→                      {!!c.email && <a href={`mailto:${c.email}`} onClick={e=>e.stopPropagation()} className="flex items-center gap-1 text-blue-600 hover:underline truncate"><Mail size={11}/>{String(c.email)}</a>}
   265→                      {!!c.phone && <a href={`tel:${c.phone}`} onClick={e=>e.stopPropagation()} className="flex items-center gap-1 text-blue-600 hover:underline"><Phone size={11}/>{String(c.phone)}</a>}
   266→                    </div>
   267→                  )}
   268→                </div>
   269→                {isExp && (
   270→                  <div className="px-4 pb-4 border-t border-gray-100 pt-3 space-y-2 text-sm">
   271→                    {!!c.address && <p className="flex items-start gap-2 text-gray-600"><MapPin size={13} className="mt-0.5 flex-shrink-0"/>{String(c.address)}</p>}
   272→                    {!!c.website && <a href={String(c.website)} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:underline text-xs block truncate">{String(c.website)}</a>}
   273→                    {!!c.notes && <p className="text-gray-500 text-xs bg-gray-50 rounded-lg p-2 leading-relaxed">{String(c.notes)}</p>}
   274→                  </div>
   275→                )}
   276→              </div>
   277→            );
   278→          })}
   279→        </div>
   280→      )}
   281→
   282→      {showModal && (
   283→        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
   284→          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-xl max-h-[90vh] overflow-y-auto">
   285→            <div className="flex items-center justify-between p-6 border-b sticky top-0 bg-white z-10">
   286→              <h2 className="text-lg font-semibold">{editing?'Edit Contact':'Add Contact'}</h2>
   287→              <button onClick={()=>setShowModal(false)} className="p-2 hover:bg-gray-100 rounded-lg"><X size={18}/></button>
   288→            </div>
   289→            <form onSubmit={handleSubmit} className="p-6 space-y-4">
   290→              <div className="grid grid-cols-2 gap-4">
   291→                <div>
   292→                  <label className="block text-sm font-medium text-gray-700 mb-1">Full Name *</label>
   293→                  <input required value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500"/>
   294→                </div>
   295→                <div>
   296→                  <label className="block text-sm font-medium text-gray-700 mb-1">Company</label>
   297→                  <input value={form.company} onChange={e=>setForm(f=>({...f,company:e.target.value}))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500"/>
   298→                </div>
   299→                <div>
   300→                  <label className="block text-sm font-medium text-gray-700 mb-1">Type</label>
   301→                  <select value={form.type} onChange={e=>setForm(f=>({...f,type:e.target.value}))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500">
   302→                    {CONTACT_TYPES.map(t=><option key={t}>{t}</option>)}
   303→                  </select>
   304→                </div>
   305→                <div>
   306→                  <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
   307→                  <select value={form.status} onChange={e=>setForm(f=>({...f,status:e.target.value}))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500">
   308→                    {STATUS_OPTIONS.map(s=><option key={s}>{s}</option>)}
   309→                  </select>
   310→                </div>
   311→                <div>
   312→                  <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
   313→                  <input type="email" value={form.email} onChange={e=>setForm(f=>({...f,email:e.target.value}))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500"/>
   314→                </div>
   315→                <div>
   316→                  <label className="block text-sm font-medium text-gray-700 mb-1">Phone</label>
   317→                  <input value={form.phone} onChange={e=>setForm(f=>({...f,phone:e.target.value}))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500"/>
   318→                </div>
   319→                <div>
   320→                  <label className="block text-sm font-medium text-gray-700 mb-1">Rating (1–5)</label>
   321→                  <select value={form.rating} onChange={e=>setForm(f=>({...f,rating:e.target.value}))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500">
   322→                    {[1,2,3,4,5].map(n=><option key={n} value={n}>{n} ★</option>)}
   323→                  </select>
   324→                </div>
   325→                <div>
   326→                  <label className="block text-sm font-medium text-gray-700 mb-1">Website</label>
   327→                  <input type="url" value={form.website} onChange={e=>setForm(f=>({...f,website:e.target.value}))} placeholder="https://…" className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500"/>
   328→                </div>
   329→                <div className="col-span-2">
   330→                  <label className="block text-sm font-medium text-gray-700 mb-1">Address</label>
